css:
.loader {--loader-bg: #ffffff;
  --loader-secondary-color: #67e8f9;
   width: calc(5*24px);
   height: 42px;
   display: flex;
   color: var(--loader-color, #0ea5e9);
   filter: drop-shadow(30px 25px 0 currentColor) drop-shadow(60px 0 0 currentColor) drop-shadow(120px 0 0 currentColor);
   clip-path: inset(0 100% 0 0);
   animation: l13 2s infinite steps(7);
}
.loader:before  {
  content: "";
   width: 24px;
   height: 20px;
   background: radial-gradient(farthest-side at right,currentColor 92%,#0000) left/20px 100% no-repeat, radial-gradient(farthest-side, currentColor 92%,#0000) right/17px 9px repeat-y;
}
@keyframes l13  {
  100% {clip-path: inset(0 -30px 0 0)}
}
